// Rate Limit Check
const rateLimitKey = 'twitter_search_rate_limit';
const rateLimitData = $execution.customData.get(rateLimitKey) || {
  remaining: 300,
  reset: Date.now() + (15 * 60 * 1000)
};

if (Date.now() > rateLimitData.reset) {
  rateLimitData.remaining = 300;
  rateLimitData.reset = Date.now() + (15 * 60 * 1000);
}

if (rateLimitData.remaining <= 5) {
  const waitMinutes = Math.ceil((rateLimitData.reset - Date.now()) / 60000);
  throw new Error(`Rate limit low (${rateLimitData.remaining} remaining). Waiting ${waitMinutes} minutes.`);
}

rateLimitData.remaining -= 1;
$execution.customData.set(rateLimitKey, rateLimitData);

return [{ 
  json: { 
    quota_remaining: rateLimitData.remaining,
    quota_reset_at: new Date(rateLimitData.reset).toISOString()
  } 
}];

// Parse Twitter API Response
const response = $input.item.json;

if (!response.data || response.data.length === 0) {
  return [];
}

const tweets = response.data;
const users = response.includes?.users || [];
const referencedTweets = response.includes?.tweets || [];

const userMap = {};
users.forEach(user => {
  userMap[user.id] = user;
});

const parsedTweets = tweets.map(tweet => {
  const author = userMap[tweet.author_id] || {};

  // Extract URLs
  const urls = tweet.entities?.urls?.map(u => u.expanded_url || u.url) || [];

  // Extract hashtags
  const hashtags = tweet.entities?.hashtags?.map(h => h.tag) || [];

  // Extract mentions
  const mentions = tweet.entities?.mentions?.map(m => m.username) || [];

  // Detect if reply or quote
  const isReply = tweet.referenced_tweets?.some(rt => rt.type === 'replied_to') || false;
  const isQuote = tweet.referenced_tweets?.some(rt => rt.type === 'quoted') || false;
  const replyToId = tweet.referenced_tweets?.find(rt => rt.type === 'replied_to')?.id;

  return {
    platform: 'twitter',
    external_id: tweet.id,
    text_content: tweet.text,
    language: tweet.lang,
    created_at: tweet.created_at,
    author_username: author.username || 'unknown',
    author_id: tweet.author_id,
    author_verified: author.verified || false,
    author_followers_count: author.public_metrics?.followers_count || 0,
    author_description: author.description || null,
    likes_count: tweet.public_metrics?.like_count || 0,
    shares_count: tweet.public_metrics?.retweet_count || 0,
    replies_count: tweet.public_metrics?.reply_count || 0,
    views_count: tweet.public_metrics?.impression_count || 0,
    urls: urls,
    hashtags: hashtags,
    mentions: mentions,
    has_media: (tweet.entities?.media && tweet.entities.media.length > 0) || false,
    is_reply: isReply,
    is_quote: isQuote,
    reply_to_id: replyToId || null,
    conversation_id: tweet.conversation_id || null,
    raw_data: tweet
  };
});

return parsedTweets.map(tweet => ({ json: tweet }));

// Deduplication using Set
const items = $input.all();
const processedIds = $execution.customData.get('processedTwitterIds') || new Set();
const newTweets = [];

for (const item of items) {
  const externalId = item.json.external_id;

  if (!processedIds.has(externalId)) {
    newTweets.push(item);
    processedIds.add(externalId);
  }
}

// Limit Set size to prevent memory issues
if (processedIds.size > 10000) {
  const idsArray = Array.from(processedIds);
  processedIds.clear();
  idsArray.slice(-10000).forEach(id => processedIds.add(id));
}

$execution.customData.set('processedTwitterIds', processedIds);

console.log(`Deduplication: ${items.length} total, ${newTweets.length} new, ${items.length - newTweets.length} duplicates filtered`);

return newTweets;

// Merge sentiment results with tweet data
const items = $input.all();
const analyzedItems = [];

for (const item of items) {
  const tweet = item.json;
  const sentiment = tweet.sentiment_analysis || {};

  // Classify threat based on heuristics
  const threatClassification = classifyThreat(tweet, sentiment);

  tweet.sentiment = sentiment;
  tweet.threat = threatClassification;

  analyzedItems.push({ json: tweet });
}

function classifyThreat(tweet, sentiment) {
  let score = 0;
  let matchedKeywords = [];
  let threatType = 'general';

  const text = tweet.text_content.toLowerCase();

  // Critical keywords (30 points each)
  const criticalKeywords = {
    'ransomware': 30,
    'data breach': 30,
    'filtración masiva': 30,
    'zero-day': 30,
    'apt': 25
  };

  // High keywords (20 points each)
  const highKeywords = {
    'phishing': 20,
    'malware': 20,
    'exploit': 20,
    'vulnerabilidad crítica': 20,
    'comprometido': 20,
    'hackeado': 20
  };

  // Medium keywords (10 points each)
  const mediumKeywords = {
    'ataque': 10,
    'amenaza': 10,
    'ciberataque': 15,
    'seguridad': 5,
    'incidente': 10
  };

  // Evaluate keywords
  Object.entries(criticalKeywords).forEach(([kw, points]) => {
    if (text.includes(kw)) {
      score += points;
      matchedKeywords.push(kw);
      threatType = 'critical_security_incident';
    }
  });

  Object.entries(highKeywords).forEach(([kw, points]) => {
    if (text.includes(kw)) {
      score += points;
      matchedKeywords.push(kw);
      if (threatType === 'general') threatType = 'security_threat';
    }
  });

  Object.entries(mediumKeywords).forEach(([kw, points]) => {
    if (text.includes(kw)) {
      score += points;
      matchedKeywords.push(kw);
    }
  });

  // Sentiment adjustment
  if (sentiment.sentiment_label === 'negative') {
    score += 15;
  }

  // Engagement adjustment
  const totalEngagement = tweet.likes_count + tweet.shares_count + (tweet.replies_count * 2);
  if (totalEngagement > 1000) {
    score += 20;
  } else if (totalEngagement > 100) {
    score += 10;
  } else if (totalEngagement > 10) {
    score += 5;
  }

  // Author credibility
  if (tweet.author_verified) {
    score += 10;
  }

  if (tweet.author_followers_count > 100000) {
    score += 15;
  } else if (tweet.author_followers_count > 10000) {
    score += 10;
  } else if (tweet.author_followers_count > 1000) {
    score += 5;
  }
// URL presence (potential phishing)
 if (tweet.urls && tweet.urls.length > 0) {
 score += 5;
 // Check for suspicious TLDs
 const suspiciousTLDs = ['.tk', '.ml', '.ga', '.cf', '.gq', '.xyz', '.top'];
 const hasSuspiciousTLD = tweet.urls.some(url => 
 suspiciousTLDs.some(tld => url.toLowerCase().includes(tld))
 );
 if (hasSuspiciousTLD) {
 score += 15;
 threatType = 'potential_phishing';
 }
 }

 // Determine criticality level
 let criticalityLevel;
 if (score >= 60) {
 criticalityLevel = 'critical';
 } else if (score >= 40) {
 criticalityLevel = 'high';
 } else if (score >= 20) {
 criticalityLevel = 'medium';
 } else {
 criticalityLevel = 'low';
 }

 // Normalize confidence
 const confidenceScore = Math.min(score / 100, 0.99);

 return {
 threat_type: threatType,
 criticality_level: criticalityLevel,
 confidence_score: confidenceScore,
 matched_keywords: matchedKeywords,
 raw_score: score
 };
}

return analyzedItems;

// Build alert content
const items = $input.all();
const alerts = [];

for (const item of items) {
 const data = item.json;

 const severityEmoji = {
 'critical': '🔴',
 'high': '🟠',
 'medium': '🟡',
 'low': '⚪'
 };

 const emoji = severityEmoji[data.threat.criticality_level] || '⚪';

 // Build Slack blocks
 const slackBlocks = JSON.stringify([
 {
 'type': 'header',
 'text': {
 'type': 'plain_text',
 'text': `${emoji} ALERTA DE AMENAZA - ${data.threat.criticality_level.toUpperCase()}`
 }
 },
 {
 'type': 'section',
 'fields': [
 {'type': 'mrkdwn', 'text': `*Plataforma:*\n${data.platform.toUpperCase()}`},
 {'type': 'mrkdwn', 'text': `*Fecha:*\n${new Date(data.created_at).toLocaleString('es-AR')}`},
 {'type': 'mrkdwn', 'text': `*Tipo:*\n${data.threat.threat_type.replace(/_/g, ' ')}`},
 {'type': 'mrkdwn', 'text': `*Confianza:*\n${(data.threat.confidence_score * 100).toFixed(1)}%`}
 ]
 },
 {
 'type': 'section',
 'text': {
 'type': 'mrkdwn',
 'text': `*Contenido:*\n>${data.text_content.substring(0, 500)}${data.text_content.length > 500 ? '...' : ''}`
 }
 },
 {
 'type': 'section',
 'fields': [
 {'type': 'mrkdwn', 'text': `*Autor:*\n@${data.author_username}${data.author_verified ? ' ✓' : ''}`},
 {'type': 'mrkdwn', 'text': `*Seguidores:*\n${data.author_followers_count.toLocaleString('es-AR')}`}
 ]
 },
 {
 'type': 'section',
 'fields': [
 {'type': 'mrkdwn', 'text': `*Engagement:*\n❤️ ${data.likes_count} | 🔄 ${data.shares_count} | 💬 ${data.replies_count}`},
 {'type': 'mrkdwn', 'text': `*Sentimiento:*\n${data.sentiment.sentiment_label} (${data.sentiment.ensemble_score?.toFixed(3) || 'N/A'})`}
 ]
 },
 {
 'type': 'section',
 'text': {
 'type': 'mrkdwn',
 'text': `*Keywords:*\n${data.threat.matched_keywords.map(k => ` \\`${k}\\``).join(', ')}`
 }
 },
 {
 'type': 'actions',
 'elements': [
 {
 'type': 'button',
 'text': {'type': 'plain_text', 'text': 'Ver Original'},
 'url': `https://twitter.com/i/status/${data.external_id}`,
 'style': 'primary'
 },
 {
 'type': 'button',
 'text': {'type': 'plain_text', 'text': 'Falso Positivo'},
 'value': `fp_${data.detection_id}`,
 'action_id': 'mark_false_positive'
 }
 ]
 },
 {
 'type': 'context',
 'elements': [
 {'type': 'mrkdwn', 'text': `Detection ID: ${data.detection_id} | Mention ID: ${data.mention_id}`}
 ]
 }
 ]);

 // Build email HTML
 const severityColor = {
 'critical': '#DC2626',
 'high': '#EA580C',
 'medium': '#F59E0B',
 'low': '#6B7280'
 };
 const color = severityColor[data.threat.criticality_level];

 const emailHtml = `
<!DOCTYPE html>
<html>
<head>
 <meta charset='UTF-8'>
 <style>
 body { font-family: Arial, sans-serif; line-height: 1.6; color: #333; }
 .container { max-width: 600px; margin: 0 auto; padding: 20px; }
 .header { background: ${color}; color: white; padding: 20px; text-align: center; border-radius: 5px 5px 0 0; }
 .content { background: #f9fafb; padding: 20px; border: 1px solid #e5e7eb; }
 .section { margin-bottom: 20px; }
 .label { font-weight: bold; color: #4b5563; }
 .value { margin-top: 5px; }
 .button { display: inline-block; padding: 12px 24px; background: ${color}; color: white; text-decoration: none; border-radius: 5px; margin: 10px 5px; }
 .footer { background: #f3f4f6; padding: 15px; text-align: center; font-size: 12px; color: #6b7280; }
 </style>
</head>
<body>
 <div class='container'>
 <div class='header'>
 <h1>${emoji} ALERTA DE AMENAZA</h1>
 <p>Criticidad: ${data.threat.criticality_level.toUpperCase()}</p>
 </div>
 <div class='content'>
 <div class='section'>
 <div class='label'>Contenido</div>
 <div class='value' style='background: white; padding: 15px; border-left: 4px solid ${color};'>
 ${data.text_content}
 </div>
 </div>
 <div class='section'>
 <div class='label'>Autor</div>
 <div class='value'>@${data.author_username} ${data.author_verified ? '✓' : ''} (${data.author_followers_count.toLocaleString('es-AR')} seguidores)</div>
 </div>
 <div style='text-align: center; margin-top: 30px;'>
 <a href='https://twitter.com/i/status/${data.external_id}' class='button'>Ver Publicación Original</a>
 </div>
 </div>
 <div class='footer'>
 <p>Detection ID: ${data.detection_id} | ${new Date().toLocaleString('es-AR')}</p>
 </div>
 </div>
</body>
</html>
` ;

 alerts.push({
 json: {
 ...data,
 alert_message: `${emoji} *ALERTA ${data.threat.criticality_level.toUpperCase()}*: ${data.text_content.substring(0, 100)}...`,
 slack_blocks: slackBlocks,
 email_subject: `[${data.threat.criticality_level.toUpperCase()}] Amenaza detectada en Twitter`,
 email_html: emailHtml
 }
 });
}

return alerts;
